// Arquivo gerado a partir da planilha 'geral elifas.xlsx'.
// Catálogo da exposição '80 anos de Elifas Andreato: Além da Moldura'.

const imagens = import.meta.glob<{ default: { url: string } }>(
  "../assets/obras/*.asset.json",
  { eager: true },
);

function imagemDaObra(num: number): string | null {
  const entry = imagens[`../assets/obras/obra-${num}.jpg.asset.json`];
  return entry ? entry.default.url : null;
}

const audios = import.meta.glob<{ default: { url: string } }>(
  "../assets/audio/*.asset.json",
  { eager: true },
);

function audioDaObra(num: number): string | null {
  const entry = audios[`../assets/audio/obra-${num}.mp3.asset.json`];
  return entry ? entry.default.url : null;
}

export interface Obra {
  num: number;
  titulo: string;
  ano: string;
  autor: string;
  tecnica: string;
  dimensao: string;
  parede: string;
  imagem: string | null;
  audio: string | null;
  descricao: string;
}

